async onProductPriceReduced(productId: string, oldPrice: number, newPrice: number) {
  const wishlistItems = await this.wishlistItemRepo.find({
    where: { productId },
    relations: ['user']
  });

  for (const item of wishlistItems) {
    await this.notificationService.create({
      userId: item.userId,
      type: 'price_drop',
      title: `💰 Prix réduit !`,
      message: `${item.product.name} est passé de ${oldPrice} à ${newPrice} FCFA`,
      productId
    });
  }
}
