// Ajouter un champ dans WishlistItem
@Column({ nullable: true })
lastStockNotificationSentAt: Date;

// Dans le service produit
async onProductRestocked(productId: string, oldStock: number, newStock: number) {
  // Ne notifier que si on passe de 0 à >0 ET pas de notification récente
  if (oldStock === 0 && newStock > 0) {
    const wishlistItems = await this.wishlistItemRepo.find({
      where: { productId },
      relations: ['user']
    });

    for (const item of wishlistItems) {
      // Éviter la double notification pour le même réapprovisionnement
      const lastNotif = item.lastStockNotificationSentAt;
      const now = new Date();

      if (!lastNotif || this.daysDiff(lastNotif, now) > 7) {
        await this.notificationService.create({
          userId: item.userId,
          type: 'back_in_stock',
          title: `📦 De retour en stock !`,
          message: `${item.product.name} est à nouveau disponible.`,
          productId
        });

        item.lastStockNotificationSentAt = now;
        await this.wishlistItemRepo.save(item);
      }
    }
  }
}
```

