// Cron job exécuté chaque jour à 8h00
@Cron('0 8 * * *')
async sendDailyPriceDropSummary() {
  // Récupérer tous les utilisateurs ayant des wishlists
  const users = await this.userRepo.find({
    relations: ['wishlist', 'wishlist.items', 'wishlist.items.product']
  });

  for (const user of users) {
    const priceDrops = [];

    for (const item of user.wishlist.items) {
      // Récupérer le dernier prix enregistré avant aujourd'hui
      const lastPrice = await this.priceHistoryRepo.findOne({
        where: { productId: item.product.id },
        order: { recordedAt: 'DESC' }
      });

      const currentPrice = item.product.price;

      if (lastPrice && lastPrice.price > currentPrice) {
        const dropPercent = ((lastPrice.price - currentPrice) / lastPrice.price) * 100;
        priceDrops.push({
          productName: item.product.name,
          oldPrice: lastPrice.price,
          newPrice: currentPrice,
          dropPercent: dropPercent.toFixed(1)
        });
      }
    }

    if (priceDrops.length > 0) {
      // Envoyer un seul email récapitulatif
      await this.emailService.sendPriceDropDigest(user.email, priceDrops);

      // Marquer les notifications comme envoyées pour éviter les doublons
      await this.markPriceDropNotified(user.id, priceDrops.map(p => p.productName));
    }
  }
}
```

**Optimisation** : Utiliser une requête SQL groupée plutôt qu'une boucle pour éviter N+1.

```typescript
async getWishlist(userId: string, sortBy: string, page: number = 1, limit: number = 20) {
  const queryBuilder = this.wishlistItemRepo
    .createQueryBuilder('item')
    .innerJoinAndSelect('item.product', 'product')
    .where('item.wishlist.userId = :userId', { userId });

  switch (sortBy) {
    case 'price_asc':
      queryBuilder.orderBy('product.price', 'ASC');
      break;
    case 'price_desc':
      queryBuilder.orderBy('product.price', 'DESC');
      break;
    case 'date_asc':
      queryBuilder.orderBy('item.addedAt', 'ASC');
      break;
    case 'date_desc':
      queryBuilder.orderBy('item.addedAt', 'DESC');
      break;
    case 'popularity':
      queryBuilder.orderBy('product.soldCount', 'DESC');
      break;
    default:
      queryBuilder.orderBy('item.addedAt', 'DESC');
  }

  const [items, total] = await queryBuilder
    .skip((page - 1) * limit)
    .take(limit)
    .getManyAndCount();

  return {
    items,
    total,
    page,
    totalPages: Math.ceil(total / limit)
  };
}
```

```typescript
async addAllWishlistToCart(userId: string) {
  const wishlist = await this.wishlistRepo.findOne({
    where: { userId },
    relations: ['items', 'items.product', 'items.product.variations']
  });

  const errors = [];
  const addedItems = [];

  for (const item of wishlist.items) {
    try {
      // Si produit sans variation, ajouter directement
      if (item.product.variations.length === 0) {
        if (item.product.stock > 0) {
          await this.cartService.addItem(userId, item.product.id, 1);
          addedItems.push(item.product.name);
        } else {
          errors.push(`${item.product.name} : rupture de stock`);
        }
      } else {
        // Pour les produits à variation, prendre la première variation disponible
        const availableVariant = item.product.variations.find(v => v.stock > 0);
        if (availableVariant) {
          await this.cartService.addItemWithVariant(userId, availableVariant.id, 1);
          addedItems.push(`${item.product.name} (${availableVariant.sku})`);
        } else {
          errors.push(`${item.product.name} : aucune variation disponible`);
        }
      }
    } catch (error) {
      errors.push(`${item.product.name} : ${error.message}`);
    }
  }

  // Vider la wishlist après ajout (optionnel, selon besoin client)
  if (addedItems.length > 0) {
    await this.wishlistRepo.clear(userId);
  }

  return {
    success: addedItems,
    errors: errors,
    message: `${addedItems.length} produit(s) ajouté(s) au panier, ${errors.length} erreur(s)`
  };
}
```
